import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [tab, setTab] = useState('users');

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post?")) return;
    try {
      await API.delete(`/posts/${id}`); 
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    // Verified: Matches path='/posts/:id' in your App.js
    navigate(`/posts/${postId}`);
  };

  // PALETTE DEFINITION
  const COLORS = {
    babyPink: '#FCE4EC',
    softPink: '#F8BBD0',
    darkGreen: '#1B5E20', // Forest Green
    lightGreen: '#E8F5E9',
    white: '#FFFFFF',
    textMain: '#0A2610',
    danger: '#D32F2F'
  };

  const styles = {
    page: {
      backgroundColor: COLORS.babyPink,
      minHeight: '100vh',
      padding: '40px 20px',
      fontFamily: '"Segoe UI", Roboto, sans-serif',
      color: COLORS.textMain,
    },
    container: {
      maxWidth: '1100px',
      margin: '0 auto',
      backgroundColor: COLORS.white,
      padding: '30px',
      borderRadius: '25px',
      boxShadow: '0 10px 30px rgba(27, 94, 32, 0.1)',
      border: `1px solid ${COLORS.softPink}`
    },
    headerSection: {
      textAlign: 'center',
      marginBottom: '30px'
    },
    title: {
      fontSize: '28px',
      color: COLORS.darkGreen,
      fontWeight: '800',
      textTransform: 'uppercase',
      letterSpacing: '1px'
    },
    tabContainer: {
      display: 'flex',
      justifyContent: 'center',
      gap: '10px',
      marginBottom: '30px'
    },
    tabButton: (isActive) => ({
      padding: '10px 24px',
      borderRadius: '50px',
      border: `2px solid ${COLORS.darkGreen}`,
      cursor: 'pointer',
      fontWeight: 'bold',
      fontSize: '14px',
      backgroundColor: isActive ? COLORS.darkGreen : 'transparent',
      color: isActive ? COLORS.white : COLORS.darkGreen,
      transition: 'all 0.3s ease',
    }),
    tableCard: {
      backgroundColor: COLORS.lightGreen,
      borderRadius: '15px',
      padding: '5px',
      overflow: 'hidden'
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
      backgroundColor: COLORS.white,
    },
    th: {
      padding: '15px',
      backgroundColor: COLORS.darkGreen,
      color: COLORS.white,
      textAlign: 'left',
      fontSize: '13px',
      textTransform: 'uppercase'
    },
    td: {
      padding: '12px 15px',
      borderBottom: `1px solid ${COLORS.softPink}`,
      fontSize: '15px'
    },
    actionGroup: {
      display: 'flex',
      gap: '8px'
    },
    btnMain: {
      padding: '8px 14px',
      borderRadius: '8px',
      border: 'none',
      backgroundColor: COLORS.darkGreen,
      color: COLORS.white,
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '12px',
      transition: 'opacity 0.2s'
    },
    btnOutline: {
      padding: '8px 14px',
      borderRadius: '8px',
      border: `1px solid ${COLORS.danger}`,
      backgroundColor: 'transparent',
      color: COLORS.danger,
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '12px'
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.headerSection}>
          <h2 style={styles.title}>Admin Control Panel</h2>
        </div>

        <div style={styles.tabContainer}>
          {['users', 'posts', 'comments'].map(t => (
            <button 
              key={t}
              style={styles.tabButton(tab === t)}
              onClick={() => setTab(t)}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        <div style={styles.tableCard}>
          <table style={styles.table}>
            <thead>
              {tab === 'users' && (
                <tr>
                  <th style={styles.th}>Name</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
              {tab === 'posts' && (
                <tr>
                  <th style={styles.th}>Title</th>
                  <th style={styles.th}>Author</th>
                  <th style={styles.th}>Actions</th>
                </tr>
              )}
              {tab === 'comments' && (
                <tr>
                  <th style={styles.th}>Author</th>
                  <th style={styles.th}>Comment</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
            </thead>
            <tbody>
              {tab === 'users' && users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}><strong>{u.name}</strong><br/><small>{u.email}</small></td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button style={styles.btnMain} onClick={() => toggleStatus(u._id)}>
                      {u.status === 'active' ? 'Ban' : 'Unban'}
                    </button>
                  </td>
                </tr>
              ))}

              {tab === 'posts' && posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name || 'Unknown'}</td>
                  <td style={styles.td}>
                    <div style={styles.actionGroup}>
                      <button style={styles.btnMain} onClick={() => viewPost(p._id)}>View</button>
                      <button style={styles.btnOutline} onClick={() => removePost(p._id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'comments' && comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}><strong>{c.author?.name}</strong></td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button style={styles.btnOutline} onClick={() => deleteComment(c._id)}>Remove</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
